import numpy as np

def resource_once_per_game_directional_swap(game_state: dict) -> dict:
    board = game_state.get('board')
    if board is None:
        return game_state

    # Standardize board to numpy array if needed
    if not isinstance(board, np.ndarray):
        board = np.array(board, dtype='<U1')

    current_player = int(game_state.get('current_player', 1))
    player_char = 'X' if current_player == 1 else 'O'
    opponent_char = 'O' if player_char == 'X' else 'X'

    # Initialize per-player resource availability on first use
    if 'resource_directional_swap_available' not in game_state:
        game_state['resource_directional_swap_available'] = {1: True, 2: True}

    if not game_state['resource_directional_swap_available'].get(current_player, False):
        return game_state

    # Find all adjacent swaps that are exactly one step away
    empties = np.argwhere(board == '_')
    own_cells = np.argwhere(board == player_char)

    if empties.size == 0 or own_cells.size == 0:
        return game_state

    nrows, ncols = board.shape
    directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    candidates = []  # list of (fx, fy, ex, ey)
    for ex, ey in empties:
        for dx, dy in directions:
            fx, fy = ex - dx, ey - dy  # piece would be adjacent to the empty
            if 0 <= fx < nrows and 0 <= fy < ncols and board[fx, fy] == player_char:
                candidates.append((fx, fy, ex, ey))

    if not candidates:
        return game_state

    # Deterministic helpful choice: prefer swaps that immediately create a 4-in-a-row possibility.
    # Otherwise, choose lexicographically earliest candidate.
    def would_create_four(x, y, ch):
        # Check lines through (x,y) for 4 consecutive of ch after placing at (x,y)
        # This is a local check using directions; board is the current board.
        # We assume the piece at (x,y) is ch.
        for dx, dy in [(1,0),(0,1),(1,1),(1,-1)]:
            count = 1
            # forward
            i = 1
            while True:
                nx, ny = x + dx*i, y + dy*i
                if 0 <= nx < nrows and 0 <= ny < ncols and board[nx, ny] == ch:
                    count += 1
                    i += 1
                else:
                    break
            # backward
            i = 1
            while True:
                nx, ny = x - dx*i, y - dy*i
                if 0 <= nx < nrows and 0 <= ny < ncols and board[nx, ny] == ch:
                    count += 1
                    i += 1
                else:
                    break
            if count >= 4:
                return True
        return False

    best = None
    for fx, fy, ex, ey in candidates:
        # After swap: destination (ex,ey) becomes player's piece; origin becomes empty.
        # The relevant immediate win is whether destination completes 4.
        creates = would_create_four(ex, ey, player_char)
        if creates:
            best = (fx, fy, ex, ey)
            break
        if best is None:
            best = (fx, fy, ex, ey)
        else:
            if (fx, fy, ex, ey) < best:
                best = (fx, fy, ex, ey)

    fx, fy, ex, ey = best
    board[fx, fy] = '_'
    board[ex, ey] = player_char

    game_state['resource_directional_swap_available'][current_player] = False
    game_state['board'] = board
    return game_state
